# Extended shapes module - imports from shapes

from shapes import IShape, BaseShape, Color, Point

class Rectangle(BaseShape, IShape):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def get_type(self) -> str:
        return "Rectangle"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"A {self.color} rectangle {self.width}x{self.height}"

class Circle(BaseShape, IShape):
    radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__(color)
        self.radius = radius

    @override
    def get_type(self) -> str:
        return "Circle"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return f"A {self.color} circle with radius {self.radius}"

@abstract
class Polygon(BaseShape):
    vertices: list[Point]

    def __init__(self, vertices: list[Point], color: Color):
        super().__init__(color)
        self.vertices = vertices

class Triangle(Polygon, IShape):
    def __init__(self, p1: Point, p2: Point, p3: Point, color: Color):
        vertices: list[Point] = [p1, p2, p3]
        super().__init__(vertices, color)

    @override
    def get_type(self) -> str:
        return "Triangle"

    @override
    def area(self) -> float:
        # Calculate using shoelace formula for triangle
        a: float = self.vertices[0].x
        b: float = self.vertices[0].y
        c: float = self.vertices[1].x
        d: float = self.vertices[1].y
        e: float = self.vertices[2].x
        f: float = self.vertices[2].y
        return abs((a * (d - f) + c * (f - b) + e * (b - d)) / 2.0)

    @override
    def perimeter(self) -> float:
        # Calculate distance between points
        result: float = 0.0
        i: int = 0
        while i < len(self.vertices):
            p1: Point = self.vertices[i]
            p2: Point = self.vertices[(i + 1) % len(self.vertices)]
            dx: float = p2.x - p1.x
            dy: float = p2.y - p1.y
            result = result + pow(dx * dx + dy * dy, 0.5)
            i = i + 1
        return result

def create_red_rectangle(width: float, height: float) -> Rectangle:
    red: Color = Color(255, 0, 0)
    return Rectangle(width, height, red)

def calculate_total_area(shapes: list[IShape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.area()
    return total
